section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-flaky-test-root-cause-taxonomy.json",
  "type": "object",
  "title": "QA Flaky Test Root-Cause Taxonomy",
  "required": [
    "taxonomy_version",
    "categories",
    "default_unknown_window_days",
    "mask_window_days"
  ],
  "additionalProperties": false,
  "properties": {
    "taxonomy_version": {
      "type": "string",
      "minLength": 1,
      "description": "Semver."
    },
    "categories": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {id, label, detectors, fix_family}."
    },
    "default_unknown_window_days": {
      "type": "integer",
      "description": "Max days a row may remain 'unknown'; \u22647."
    },
    "mask_window_days": {
      "type": "integer",
      "description": "Max days a masked row may live without a fix plan; \u226430."
    }
  }
}

example.code:
{
  "taxonomy_version": "1.0.0",
  "categories": [
    {
      "id": "time",
      "label": "Time-sensitive",
      "detectors": [
        "assert .* in .* sleep",
        "now\\(\\) compared"
      ],
      "fix_family": "freezegun + monotonic clock"
    },
    {
      "id": "order",
      "label": "Order-dependent",
      "detectors": [
        "passes alone, fails in suite"
      ],
      "fix_family": "explicit setup/teardown + pytest-randomly"
    }
  ],
  "default_unknown_window_days": 7,
  "mask_window_days": 30
}
